'use client'
import { useEffect, useState, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { getUser, getToken, isAdmin } from '@/lib/eso-auth'

type Tab = 'users' | 'scans' | 'tiers' | 'stats'

const TIER_COLOR: Record<string,string> = { free:'#64748b', pro:'#00aaff', enterprise:'#a78bfa', admin:'#00ffaa' }
const STATUS_COLOR: Record<string,string> = { completed:'#00ffaa', failed:'#ff3a5c', running:'#00aaff', planning:'#ffd700', pending:'#475569' }

async function adminFetch(path: string, opts?: RequestInit) {
  const token = getToken()
  const res = await fetch(`/api/eso${path}`, {
    ...opts,
    headers: { 'Content-Type':'application/json', ...(token?{Authorization:`Bearer ${token}`}:{}), ...opts?.headers },
  })
  if (!res.ok) throw new Error(`${res.status}: ${await res.text()}`)
  return res.json()
}

export default function EsoAdminPage() {
  const router = useRouter()
  const [tab,    setTab]    = useState<Tab>('stats')
  const [stats,  setStats]  = useState<any>(null)
  const [users,  setUsers]  = useState<any[]>([])
  const [scans,  setScans]  = useState<any[]>([])
  const [tiers,  setTiers]  = useState<any[]>([])
  const [loading,setLoading]= useState(false)
  const [search, setSearch] = useState('')
  const [msg,    setMsg]    = useState('')

  // Auth guard
  useEffect(() => {
    if (!isAdmin()) { router.push('/login'); return }
  }, [router])

  const load = useCallback(async () => {
    setLoading(true)
    try {
      if (tab === 'stats') {
        const s = await adminFetch('/admin/stats')
        setStats(s)
      } else if (tab === 'users') {
        const u = await adminFetch('/admin/users?limit=100')
        setUsers(u.users ?? [])
      } else if (tab === 'scans') {
        const s = await adminFetch('/admin/scans?limit=50')
        setScans(s.scans ?? [])
      } else if (tab === 'tiers') {
        const t = await adminFetch('/admin/tiers')
        setTiers(t.tiers ?? [])
      }
    } catch (e: any) {
      setMsg(`Error: ${e.message}`)
    }
    setLoading(false)
  }, [tab])

  useEffect(() => { load() }, [load])

  async function setTier(userId: string, tier: string) {
    try {
      await adminFetch('/admin/users/tier', { method:'POST', body:JSON.stringify({user_id:userId, tier}) })
      setMsg(`✓ ${userId} upgraded to ${tier}`)
      load()
    } catch (e: any) { setMsg(`✗ ${e.message}`) }
  }

  async function toggleUser(userId: string, active: boolean) {
    try {
      await adminFetch('/admin/users/status', { method:'POST', body:JSON.stringify({user_id:userId, is_active:active}) })
      setMsg(`✓ User ${active?'enabled':'disabled'}`)
      load()
    } catch (e: any) { setMsg(`✗ ${e.message}`) }
  }

  async function resetQuota(userId: string) {
    try {
      await adminFetch('/admin/users/reset-quota', { method:'POST', body:JSON.stringify({user_id:userId}) })
      setMsg(`✓ Quota reset for ${userId}`)
      load()
    } catch (e: any) { setMsg(`✗ ${e.message}`) }
  }

  const filteredUsers = users.filter(u =>
    !search || u.username?.includes(search) || u.email?.includes(search) || u.user_id?.includes(search)
  )

  const TABS: {id:Tab, label:string, icon:string}[] = [
    {id:'stats',  label:'Overview', icon:'📊'},
    {id:'users',  label:'Users',    icon:'👥'},
    {id:'scans',  label:'Scans',    icon:'🔍'},
    {id:'tiers',  label:'Tiers',    icon:'🎯'},
  ]

  const sCell = "px-4 py-2.5 font-mono text-[11px]"

  return (
    <div className="p-3 sm:p-5">
      {/* Header */}
      <div className="flex items-center justify-between mb-5 flex-wrap gap-3">
        <div>
          <h1 className="text-2xl font-black">ESO <span className="text-accent">Admin</span></h1>
          <p className="font-mono text-[11px] text-slate-500 mt-1">
            Logged in as <span className="text-accent">{getUser()?.username}</span> · role: admin
          </p>
        </div>
        <button onClick={load} className="font-mono text-[11px] text-slate-500 hover:text-slate-300 cursor-pointer transition-colors">
          ↻ Refresh
        </button>
      </div>

      {/* Feedback */}
      {msg && (
        <div className="mb-4 p-3 rounded-lg border font-mono text-[11px]"
          style={msg.startsWith('✓')
            ?{background:'rgba(0,255,170,0.06)',borderColor:'rgba(0,255,170,0.2)',color:'#00ffaa'}
            :{background:'rgba(255,58,92,0.06)',borderColor:'rgba(255,58,92,0.2)',color:'#ff3a5c'}}>
          {msg}
          <button onClick={()=>setMsg('')} className="ml-3 opacity-50 hover:opacity-100">✕</button>
        </div>
      )}

      {/* Tabs */}
      <div className="flex gap-1 mb-5 p-1 rounded-xl" style={{background:'rgba(255,255,255,0.03)',border:'1px solid rgba(255,255,255,0.06)'}}>
        {TABS.map(t => (
          <button key={t.id} onClick={()=>setTab(t.id)}
            className="flex-1 flex items-center justify-center gap-2 py-2 rounded-lg font-mono text-[11px] font-bold cursor-pointer transition-all"
            style={tab===t.id
              ?{background:'rgba(0,255,170,0.1)',borderColor:'rgba(0,255,170,0.25)',color:'#00ffaa',border:'1px solid rgba(0,255,170,0.25)'}
              :{color:'#475569',border:'1px solid transparent'}}>
            <span>{t.icon}</span><span className="hidden sm:inline">{t.label}</span>
          </button>
        ))}
      </div>

      {loading && <div className="font-mono text-[11px] text-slate-600 animate-pulse py-8 text-center">Loading...</div>}

      {/* ── STATS TAB ── */}
      {tab==='stats' && stats && !loading && (
        <div className="space-y-4">
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            {[
              {label:'Total Users', val:stats.users?.total??0,           color:'#00aaff'},
              {label:'Total Scans', val:stats.scans?.total??0,           color:'#a78bfa'},
              {label:'Last 24h',    val:stats.scans?.last_24h??0,        color:'#00ffaa'},
              {label:'Findings',   val:stats.findings?.total??0,         color:'#ff8c42'},
            ].map((s,i) => (
              <div key={i} className="glass px-4 py-3">
                <div className="font-mono text-2xl font-bold" style={{color:s.color}}>{s.val}</div>
                <div className="font-mono text-[9px] uppercase tracking-widest text-slate-600 mt-1">{s.label}</div>
              </div>
            ))}
          </div>

          {/* Users by tier */}
          <div className="glass p-4">
            <div className="font-mono text-[9px] uppercase tracking-widest text-slate-600 mb-3">Users by Tier</div>
            <div className="flex flex-wrap gap-3">
              {Object.entries(stats.users?.by_tier??{}).map(([tier,count]:any) => (
                <div key={tier} className="px-4 py-2 rounded-lg border" style={{borderColor:`${TIER_COLOR[tier]??'#475569'}40`,background:`${TIER_COLOR[tier]??'#475569'}0d`}}>
                  <div className="font-mono text-lg font-bold" style={{color:TIER_COLOR[tier]??'#475569'}}>{count}</div>
                  <div className="font-mono text-[9px] text-slate-600 capitalize">{tier}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Recent scans */}
          <div className="glass overflow-hidden">
            <div className="px-4 py-2.5 border-b border-white/[0.06]">
              <span className="font-mono text-[10px] text-accent uppercase tracking-widest">Recent Scans (all users)</span>
            </div>
            <div className="divide-y divide-white/[0.03]">
              {(stats.recent_scans??[]).map((s:any) => (
                <div key={s.process_id} className="flex items-center justify-between px-4 py-2.5">
                  <div>
                    <span className="text-[12px] text-slate-200">{s.target||'—'}</span>
                    <span className="font-mono text-[10px] text-slate-600 ml-2">by {s.username}</span>
                  </div>
                  <div className="flex items-center gap-3">
                    <span className="font-mono text-[10px] text-slate-500">{s.findings_count} findings</span>
                    <span className="font-mono text-[9px] px-2 py-[2px] rounded"
                      style={{color:STATUS_COLOR[s.status]??'#475569',background:'rgba(255,255,255,0.05)'}}>
                      {s.status}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ── USERS TAB ── */}
      {tab==='users' && !loading && (
        <div className="space-y-3">
          <div className="glass p-3">
            <input value={search} onChange={e=>setSearch(e.target.value)}
              placeholder="Search by username, email or user_id..."
              className="w-full bg-white/[0.04] border border-white/[0.08] rounded-lg px-3 py-2 font-mono text-[11px] text-slate-300 outline-none focus:border-accent/30 transition-colors placeholder-slate-700"/>
          </div>
          <div className="glass overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full border-collapse">
                <thead>
                  <tr style={{background:'rgba(255,255,255,0.015)',borderBottom:'1px solid rgba(255,255,255,0.06)'}}>
                    {['User','Email','Tier','Scans Today','Total','Status','Actions'].map(h => (
                      <th key={h} className="font-mono text-[9px] uppercase tracking-widest text-slate-600 text-left px-4 py-2.5">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {filteredUsers.map(u => (
                    <tr key={u.user_id} className="border-b border-white/[0.03] hover:bg-white/[0.02] transition-colors">
                      <td className={sCell}>
                        <div className="text-slate-200 font-semibold">{u.username}</div>
                        <div className="text-slate-600 text-[9px] font-mono">{u.user_id}</div>
                      </td>
                      <td className={`${sCell} text-slate-500`}>{u.email}</td>
                      <td className={sCell}>
                        <select
                          value={u.tier??'free'}
                          onChange={e=>setTier(u.user_id, e.target.value)}
                          className="bg-white/[0.04] border border-white/[0.08] rounded px-2 py-1 font-mono text-[10px] cursor-pointer outline-none"
                          style={{color:TIER_COLOR[u.tier??'free']}}>
                          {['free','pro','enterprise','admin'].map(t => (
                            <option key={t} value={t} style={{color:TIER_COLOR[t]}}>{t}</option>
                          ))}
                        </select>
                      </td>
                      <td className={`${sCell} font-mono text-slate-300`}>{u.scans_today??0}</td>
                      <td className={`${sCell} font-mono text-slate-500`}>{u.total_scans??0}</td>
                      <td className={sCell}>
                        <span className="font-mono text-[9px] font-bold" style={{color:u.is_active?'#00ffaa':'#ff3a5c'}}>
                          {u.is_active?'Active':'Disabled'}
                        </span>
                      </td>
                      <td className={`${sCell}`}>
                        <div className="flex items-center gap-3">
                          <button onClick={()=>toggleUser(u.user_id,!u.is_active)}
                            className="font-mono text-[9px] cursor-pointer transition-colors hover:opacity-80"
                            style={{color:u.is_active?'#ff3a5c':'#00ffaa'}}>
                            {u.is_active?'Disable':'Enable'}
                          </button>
                          <button onClick={()=>resetQuota(u.user_id)}
                            className="font-mono text-[9px] text-slate-500 hover:text-slate-300 cursor-pointer transition-colors">
                            Reset quota
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {filteredUsers.length===0 && (
                <div className="p-8 text-center font-mono text-[11px] text-slate-600">No users found</div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* ── SCANS TAB ── */}
      {tab==='scans' && !loading && (
        <div className="glass overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <thead>
                <tr style={{background:'rgba(255,255,255,0.015)',borderBottom:'1px solid rgba(255,255,255,0.06)'}}>
                  {['Target','User','Tier','Status','Risk','Findings','Duration','Date'].map(h => (
                    <th key={h} className="font-mono text-[9px] uppercase tracking-widest text-slate-600 text-left px-4 py-2.5">{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {scans.map(s => (
                  <tr key={s.process_id} className="border-b border-white/[0.03] hover:bg-white/[0.02] transition-colors">
                    <td className={sCell}>
                      <div className="text-slate-200">{s.target||'—'}</div>
                      <div className="text-slate-600 text-[9px] font-mono">{s.process_id}</div>
                    </td>
                    <td className={`${sCell} text-slate-400`}>{s.username}</td>
                    <td className={sCell}>
                      <span className="font-mono text-[9px]" style={{color:TIER_COLOR[s.tier??'free']}}>{s.tier??'free'}</span>
                    </td>
                    <td className={sCell}>
                      <span className="font-mono text-[9px] px-2 py-[2px] rounded"
                        style={{color:STATUS_COLOR[s.status]??'#64748b',background:'rgba(255,255,255,0.05)'}}>
                        {s.status}
                      </span>
                    </td>
                    <td className={`${sCell} font-mono`} style={{color:s.risk_level==='critical'?'#ff3a5c':s.risk_level==='high'?'#ff8c42':s.risk_level==='medium'?'#ffd700':'#64748b'}}>
                      {(s.risk_level||'—').toUpperCase()}
                    </td>
                    <td className={`${sCell} font-mono text-accent2`}>{s.findings_count??0}</td>
                    <td className={`${sCell} font-mono text-slate-500`}>{s.duration_seconds?`${(s.duration_seconds/60).toFixed(1)}m`:'—'}</td>
                    <td className={`${sCell} font-mono text-slate-600 text-[10px]`}>{s.created_at?new Date(s.created_at).toLocaleDateString():'—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
            {scans.length===0 && <div className="p-8 text-center font-mono text-[11px] text-slate-600">No scans found</div>}
          </div>
        </div>
      )}

      {/* ── TIERS TAB ── */}
      {tab==='tiers' && !loading && (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {tiers.map(t => (
            <div key={t.tier} className="glass p-4" style={{borderColor:`${TIER_COLOR[t.tier]??'#475569'}40`}}>
              <div className="font-mono text-[10px] uppercase tracking-widest mb-3" style={{color:TIER_COLOR[t.tier]??'#475569'}}>
                {t.tier}
              </div>
              <div className="space-y-1.5">
                {[
                  ['Scans/day',      t.scans_per_day],
                  ['Max concurrent', t.max_concurrent],
                  ['Max duration',   `${t.max_scan_duration}s`],
                  ['Tools',          (t.allowed_tools??[]).join(', ')],
                  ['AI analysis',    t.ai_analysis_enabled?'✓':'✗'],
                  ['Proposals',      t.proposals_enabled?'✓':'✗'],
                  ['Scheduling',     t.scheduling_enabled?'✓':'✗'],
                  ['Teams',          t.teams_enabled?'✓':'✗'],
                  ['PDF reports',    t.pdf_reports_enabled?'✓':'✗'],
                  ['API access',     t.api_access_enabled?'✓':'✗'],
                ].map(([label,val]) => (
                  <div key={String(label)} className="flex items-center justify-between py-1 border-b border-white/[0.04] last:border-0">
                    <span className="font-mono text-[10px] text-slate-600">{label}</span>
                    <span className="font-mono text-[10px] text-slate-300">{String(val)}</span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}
